import subprocess

def get_last_login_records(username: str) -> str:
    """
    Queries the system's SSH login history for a specific user using the 'last' command.

    This function executes the 'last' system command safely using subprocess.
    It filters the output for the provided username.

    Args:
        username (str): The username to query login records for.

    Returns:
        str: A string containing the formatted login records, a specific message if no records
             are found, or an error message if the query fails.
    """
    # 1. Input Validation
    if not username or not isinstance(username, str):
        return "Error: Invalid username provided."

    # 2. Security: Sanitize input to prevent command injection
    # Although subprocess.run with a list of arguments prevents shell injection,
    # we enforce a strict whitelist of allowed characters for usernames.
    # Valid characters: alphanumeric, dot, hyphen, underscore.
    if not all(c.isalnum() or c in ('.', '-', '_') for c in username):
        return "Error: Username contains invalid characters."

    # 3. Prepare the command
    # 'last' is the standard utility to show login records.
    # '-w' flag ensures full width (display full IP/hostname) for better readability.
    command = ["last", "-w", username]

    try:
        # 4. Execute the command securely
        # shell=False is the default and crucial for security (prevents shell injection).
        # capture_output=True captures stdout and stderr.
        # text=True decodes output as UTF-8 strings.
        # timeout prevents the process from hanging indefinitely.
        result = subprocess.run(
            command,
            capture_output=True,
            text=True,
            timeout=10
        )

        # 5. Process Output
        # 'last' typically returns 0 on success, even if no records are found (printing nothing).
        # We prioritize checking stdout. If empty, we return a user-friendly message.

        if result.returncode == 0:
            if result.stdout and result.stdout.strip():
                # Filter output to ensure only lines for the specific user are returned
                # This handles cases where 'last' might return other users if the command behaves unexpectedly
                filtered_lines = [
                    line for line in result.stdout.strip().split('\n')
                    if line.startswith(username + ' ')
                ]
                if filtered_lines:
                    return '\n'.join(filtered_lines)
                else:
                    return "No login records found for user '{}'.".format(username)
            else:
                return "No login records found for user '{}'.".format(username)
        else:
            # If the command returned a non-zero exit code, check stderr.
            if result.stderr and result.stderr.strip():
                return "Error querying history: {}".format(result.stderr.strip())
            else:
                # Fallback if exit code is error but no stderr was produced
                return "No login records found for user '{}'.".format(username)

    except subprocess.TimeoutExpired:
        return "Error: Command timed out while fetching records."
    except FileNotFoundError:
        return "Error: 'last' command not found. Ensure this is a Linux environment with 'last' installed."
    except Exception as e:
        return "Error: An unexpected error occurred: {}".format(str(e))
